from abc import ABC, abstractmethod

# 1. Ürün Arayüzü (Product Interface)
class Document(ABC):
    """
    Belge arayüzünü tanımlar.
    """
    @abstractmethod
    def open(self) -> str:
        pass

    @abstractmethod
    def save(self) -> str:
        pass

# 2. Somut Ürünler (Concrete Products)
class PdfDocument(Document):
    """
    PDF belge tipini uygulayan somut ürün.
    """
    def open(self) -> str:
        return "PDF Belgesi açılıyor."

    def save(self) -> str:
        return "PDF Belgesi kaydediliyor."

class WordDocument(Document):
    """
    Word belge tipini uygulayan somut ürün.
    """
    def open(self) -> str:
        return "Word Belgesi açılıyor."

    def save(self) -> str:
        return "Word Belgesi kaydediliyor."

# 3. Yaratıcı Arayüzü (Creator Interface)
class DocumentCreator(ABC):
    """
    Fabrika metodunu (create_document) bildiren soyut yaratıcı sınıf.
    Ayrıca, fabrika metodunun sonucuna bağlı olan bazı temel mantıkları da tanımlayabilir.
    """
    @abstractmethod
    def create_document(self) -> Document:
        """
        Belge nesneleri döndürmesi gereken fabrika metodu.
        Bu metod, alt sınıflar tarafından geçersiz kılınır.
        """
        pass

    def perform_document_operations(self) -> str:
        """
        Yaratıcının çekirdek mantığı. Fabrika metodunu çağırır.
        """
        document = self.create_document()  # Fabrika metodu çağrılıyor
        result = f"Yaratıcı: Belge oluşturuldu ve üzerinde işlemler yapılıyor:\n"
        result += f"- {document.open()}\n"
        result += f"- {document.save()}"
        return result

# 4. Somut Yaratıcılar (Concrete Creators)
class PdfCreator(DocumentCreator):
    """
    PDF belge oluşturan somut yaratıcı.
    Fabrika metodunu PDFDocument döndürecek şekilde uygular.
    """
    def create_document(self) -> Document:
        return PdfDocument()

class WordCreator(DocumentCreator):
    """
    Word belge oluşturan somut yaratıcı.
    Fabrika metodunu WordDocument döndürecek şekilde uygular.
    """
    def create_document(self) -> Document:
        return WordDocument()

# İstemci kodu
def client_code(creator: DocumentCreator):
    print(f"İstemci: Yaratıcı ile işlem yapılıyor: \n{creator.perform_document_operations()}\n")

if __name__ == "__main__":
    print("Uygulama: PDF Oluşturucu ile başlatıldı.")
    client_code(PdfCreator())

    print("Uygulama: Word Oluşturucu ile başlatıldı.")
    client_code(WordCreator())
